/**
 * InheritsProcessor
 * Handles @Inherits annotations for prototype inheritance.
 */
module.exports = {
  processScan(meta, ctx) {},

  /**
   * Applies inheritance during the Instantiate stage.
   */
  processInstantiate(meta, ctx) {
    const baseClass = ctx.container.resolve(meta.args[0]);
    Object.setPrototypeOf(meta.classRef.prototype, baseClass.prototype);
    ctx.log.push(`@Inherits applied: ${meta.className} ← ${meta.args[0]}`);
  },

  processDI(meta, ctx) {},

  processInit(meta, ctx) {},

  processRun(meta, ctx) {}
};